这是一个私有函数。

```
void MainWindow::setupDeviceData()
{
    if (!modbusDevice)
        return;

    for (quint16 i = 0; i setData(QModbusDataUnit::Coils, i, coilButtons.button(i)->isChecked());

    for (quint16 i = 0; i setData(QModbusDataUnit::DiscreteInputs, i,
            discreteButtons.button(i)->isChecked());
